const saludos = ['hola','hi','hello','buenas','buenos','buen','inicio','menu','start','0'];
let msg;
if (saludos.some(s => text.startsWith(s)) || text === '') {
  msg = MENU;
} else if (text === '1' || text.includes('menu') || text.includes('menú') || text.includes('precio') || text.includes('carne')) {
  msg = MENU_ITEMS;
} else if (text === '2' || text.includes('reserv') || text.includes('mesa')) {
  msg = RESERVAR;
} else if (text === '3' || text.includes('pedir') || text.includes('orden') || text.includes('pedido') || text.includes('llevar')) {
  msg = PEDIR;
} else if (text === '4' || text.includes('horario') || text.includes('ubicac') || text.includes('direcc') || text.includes('donde')) {
  msg = HORARIOS;
} else if (text.includes('parrillada') || text.includes('parrilla') || text.includes('asado')) {
  msg = MENU_ITEMS;
} else {
  msg = MENU;
}

return [{ json: { from, mensaje_respuesta: msg } }];
